            where: {id},
            relations: ["raceEntry", "raceEntry.boat", "raceEntry.boat.boatClass", "raceEntry.race", "raceEntry.race.raceClass", "raceEntry.race.raceClass.handicapType"],
        });
    }

    //#endregion
}

import {Request, Response, Router} from 'express';
import {FetchProvider} from "./data/fetch-provider.service";
import {Boat, BoatClass, HandicapType, Race, RaceClass, RaceClassType, RaceEntry, RaceOutcome, Series} from "./entity/entities";
import multer from "multer";

const router = Router();
const upload = multer({storage: multer.memoryStorage()});
let fetchProvider: FetchProvider;

//#region Race
router.get('/race', async (req: Request, res: Response) => {
    try {
        const races = await getProvider().getRaces();
        res.json(races);
    } catch (error) {
        res.status(500).json({error: "Internal Server Error"});
    }
});
